#!/usr/bin/env bash
set -e; DEST=${ADXC_INSTALL_DIR:-/opt/adxc}; KEEP=no; for a in "$@"; do case "$a" in --keep-user-runtime) KEEP=yes;; *) echo "Unknown option: $a"; exit 1;; esac; done; [ "$(id -u)" -eq 0 ] || { echo "ERROR: uninstall.sh must be run as root" >&2; exit 1; }; rm -rf "$DEST"; echo "aDXC-GAMA removed from $DEST"; if [ "$KEEP" = no ]; then rm -rf /root/.adxc 2>/dev/null || true; for h in /home/*; do [ -d "$h/.adxc" ] && rm -rf "$h/.adxc"; done; echo "User runtime directories ~/.adxc were purged."; else echo "User runtime directories ~/.adxc were intentionally left untouched."; fi
